$(document).ready(function(){var a=$("#sitepath").val(),e=$("#usersupportticketTable").DataTable({rowCallback:function(a,e,t){"N"==e.user_read&&$("td",a).css("background-color","#DBA514")},processing:!0,serverSide:!0,searching:!1,ajax:{url:a+"user/support-ticket-data",type:"POST",data:function(a){a.csrf_npb_name=$(".csrftoken").val(),a.searchName=$("#textSearch").val(),a.searchByStatus=$("#statusSearch").val()},complete:function(a){var e=JSON.parse(a.responseText);$(".csrftoken").attr("value",e.token)}},columns:[{data:"ticket_id"},{data:"user"},{data:"subject"},{data:"ticketDate"},{data:"ticketStatus"},{data:"action"}]});$("#textSearch").keyup(function(){e.draw()}),$("#statusSearch").change(function(){e.draw()}),$(".createticket").click(function(){$("#ticketCreateFrm").slideDown(),$(this).hide()}),$(".schedulecallbtn").click(function(){$("#calllogreqform").slideDown(),$(this).hide()});var t=$("#walletTable").DataTable({rowCallback:function(a,e,t){"N"==e.user_read&&$("td",a).css("background-color","#DBA514")},processing:!0,serverSide:!0,searching:!1,ajax:{url:a+"user/wallet-list-data",type:"POST",data:function(a){a.csrf_npb_name=$(".csrftoken").val(),a.searchName=$("#textSearch").val(),a.searchByStatus=$("#statusSearch").val()},complete:function(a){var e=JSON.parse(a.responseText);$(".csrftoken").attr("value",e.token)}},columns:[{data:"transaction_ref"},{data:"wallet_amount"},{data:"type"},{data:"date_added"},{data:"buyStatus"}]});$("#textSearch").keyup(function(){t.draw()}),$("#statusSearch").change(function(){t.draw()});var c=$("#usercallschedulkleTable").DataTable({processing:!0,serverSide:!0,searching:!1,ajax:{url:a+"scheduledcallsAction",type:"POST",data:function(a){a.csrf_npb_name=$(".csrftoken").val(),a.searchName=$("#textSearchCall").val(),a.searchTimeSchedulecall=$("#textSearchTime").val(),a.searchByStatus=$("#statusSearchCall").val()},complete:function(a){if(null!=a.responseText)var e=JSON.parse(a.responseText);$(".csrftoken").attr("value",e.token)}},columns:[{data:"phone"},{data:"scheduledtime"},{data:"note"},{data:"status"}]});$("#textSearchCall").keyup(function(){c.draw()}),$("#textSearchTime").change(function(){c.draw()}),$("#statusSearchCall").change(function(){c.draw()})});